import React, { useState } from "react";

function GroupModal({ friends, onCreateGroup, onClose }) {
  const [groupName, setGroupName] = useState("");
  const [selected, setSelected] = useState([]);

  const toggleSelect = (id) => {
    setSelected((prev) =>
      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]
    );
  };

  const handleSubmit = () => {
    if (!groupName || selected.length === 0) {
      alert("Please enter a group name and select members");
      return;
    }
    onCreateGroup(groupName, selected);
    onClose();
  };

  return (
    <div style={{
      position: "fixed", top: "50%", left: "50%",
      transform: "translate(-50%, -50%)",
      background: "#fff", padding: "20px",
      border: "1px solid #ccc", borderRadius: "8px"
    }}>
      <h3>Create New Group</h3>
      <input
        placeholder="Group Name"
        value={groupName}
        onChange={(e) => setGroupName(e.target.value)}
        style={{ width: "100%", marginBottom: "10px", padding: "8px" }}
      />
      <div style={{ maxHeight: "150px", overflowY: "scroll", marginBottom: "10px" }}>
        {friends.map((f) => (
          <label key={f._id} style={{ display: "block" }}>
            <input
              type="checkbox"
              checked={selected.includes(f.userId)}
              onChange={() => toggleSelect(f.userId)}
            />
            {f.displayName || f.userId}
          </label>
        ))}
      </div>
      <button onClick={handleSubmit} style={{ marginRight: "10px" }}>Create ✅</button>
      <button onClick={onClose}>Cancel ❌</button>
    </div>
  );
}

export default GroupModal;
